B.ZT=new A.l(B.af,["Hemorrhagic Septicemia (HS)","\u06c1\u06cc\u0645\u0648\u0631\u06cc\u062c\u06a9 \u0633\u06cc\u067e\u0679\u06cc \u0633\u06cc\u0645\u06cc\u0627 (HS)","High fever, throat swelling, breathing difficulty, sudden weakness.","\u062a\u06cc\u0632 \u0628\u062e\u0627\u0631\u060c \u06af\u0644\u06d2 \u06a9\u06cc \u0633\u0648\u062c\u0646\u060c \u0633\u0627\u0646\u0633 \u0645\u06cc\u06ba \u062f\u0634\u0648\u0627\u0631\u06cc\u060c \u0627\u0686\u0627\u0646\u06a9 \u06a9\u0645\u0632\u0648\u0631\u06cc\u06d4","Immediate vet visit, early antibiotics/anti-inflammatory, isolate animal, urgent HS vaccination program for herd.","\u0641\u0648\u0631\u0627\u064b \u0648\u06cc\u0679 \u0633\u06d2 \u0631\u0627\u0628\u0637\u06c1 \u06a9\u0631\u06cc\u06ba\u060c \u062c\u0644\u062f \u0627\u06cc\u0646\u0679\u06cc \u0628\u0627\u06cc\u0648\u0679\u06a9/\u0633\u0648\u0632\u0634 \u06a9\u0645 \u06a9\u0631\u0646\u06d2 \u0648\u0627\u0644\u06cc \u062f\u0648\u0627\u060c \u062c\u0627\u0646\u0648\u0631 \u06a9\u0648 \u0627\u0644\u06af \u0631\u06a9\u06be\u06cc\u06ba\u060c \u0631\u06cc\u0648\u0691 \u06a9\u06d2 \u0644\u06cc\u06d2 HS \u0648\u06cc\u06a9\u0633\u06cc\u0646 \u067e\u0631\u0648\u06af\u0631\u0627\u0645 \u06a9\u0631\u06cc\u06ba\u06d4"],t.w)
B.ZW=new A.l(B.af,["Foot-and-Mouth Disease (FMD)","\u0645\u0646\u06c1 \u06a9\u06be\u0631 \u06a9\u06cc \u0628\u06cc\u0645\u0627\u0631\u06cc (FMD)","Mouth blisters, excessive salivation, lameness, drop in feed and milk.","\u0645\u0646\u06c1 \u0645\u06cc\u06ba \u0686\u06be\u0627\u0644\u06d2\u060c \u0632\u06cc\u0627\u062f\u06c1 \u0631\u0627\u0644\u060c \u0644\u0646\u06af\u0691\u0627\u06c1\u0679\u060c \u062e\u0648\u0631\u0627\u06a9 \u0627\u0648\u0631 \u062f\u0648\u062f\u06be \u0645\u06cc\u06ba \u06a9\u0645\u06cc\u06d4","Supportive care, mouth/hoof antiseptic wash, pain control, strict isolation and disinfection; vaccinate unaffected stock.","\u0633\u067e\u0648\u0631\u0679\u0648 \u06a9\u06cc\u0626\u0631\u060c \u0645\u0646\u06c1/\u06a9\u06be\u0631 \u06a9\u06cc \u062c\u0631\u0627\u062b\u06cc\u0645 \u06a9\u0634 \u0635\u0641\u0627\u0626\u06cc\u060c \u062f\u0631\u062f \u06a9\u0627 \u06a9\u0646\u0679\u0631\u0648\u0644\u060c \u0633\u062e\u062a \u0639\u0644\u06cc\u062d\u062f\u06af\u06cc \u0627\u0648\u0631 \u062c\u0631\u0627\u062b\u06cc\u0645 \u06a9\u0634\u06cc\u061b \u063a\u06cc\u0631 \u0645\u062a\u0627\u062b\u0631\u06c1 \u062c\u0627\u0646\u0648\u0631\u0648\u06ba \u06a9\u06cc \u0648\u06cc\u06a9\u0633\u06cc\u0646 \u06a9\u0631\u06cc\u06ba\u06d4"],t.w)
B.ZX=new A.l(B.af,["Mastitis","\u062a\u06be\u0646 \u06a9\u06cc \u0633\u0648\u0632\u0634 (\u0645\u0627\u0633\u0679\u0627\u0626\u0679\u0633)","Hot painful udder, clots/watery milk, reduced milk yield.","\u062a\u06be\u0646 \u06af\u0631\u0645 \u0627\u0648\u0631 \u062f\u0631\u062f\u0646\u0627\u06a9\u060c \u062f\u0648\u062f\u06be \u0645\u06cc\u06ba \u0644\u0648\u062a\u06be\u0691\u06d2/\u067e\u062a\u0644\u0627 \u067e\u0646\u060c \u062f\u0648\u062f\u06be \u0645\u06cc\u06ba \u06a9\u0645\u06cc\u06d4","Milk culture where possible, vet-prescribed intramammary treatment, frequent stripping, udder hygiene and dry bedding.","\u0645\u0645\u06a9\u0646 \u06c1\u0648 \u062a\u0648 \u062f\u0648\u062f\u06be \u0679\u06cc\u0633\u0679\u060c \u0648\u06cc\u0679 \u06a9\u06d2 \u0645\u0634\u0648\u0631\u06d2 \u0633\u06d2 \u062a\u06be\u0646 \u06a9\u0627 \u0639\u0644\u0627\u062c\u060c \u0628\u0627\u0631 \u0628\u0627\u0631 \u062f\u0648\u062f\u06be \u0646\u06a9\u0627\u0644\u0646\u0627\u060c \u062a\u06be\u0646 \u0635\u0641\u0627\u0626\u06cc \u0627\u0648\u0631 \u062e\u0634\u06a9 \u0628\u0686\u06be\u0648\u0646\u0627\u06d4"],t.w)
B.ZG=new A.l(B.af,[u.Z,u.I,"Red/dark urine, anemia and weakness; high fever is more suggestive of babesiosis, while recent calving + low phosphorus intake may indicate nutritional hemoglobinuria.","\u0633\u0631\u062e/\u06af\u06c1\u0631\u0627 \u067e\u06cc\u0634\u0627\u0628\u060c \u062e\u0648\u0646 \u06a9\u06cc \u06a9\u0645\u06cc \u0627\u0648\u0631 \u06a9\u0645\u0632\u0648\u0631\u06cc\u061b \u062a\u06cc\u0632 \u0628\u062e\u0627\u0631 \u0639\u0645\u0648\u0645\u0627\u064b \u0628\u06cc\u0628\u06cc\u0633\u06cc\u0648\u0633\u0633 \u06a9\u06cc \u0637\u0631\u0641 \u0627\u0634\u0627\u0631\u06c1 \u06a9\u0631\u062a\u0627 \u06c1\u06d2 \u062c\u0628\u06a9\u06c1 \u0628\u0686\u06d2 \u06a9\u06d2 \u0628\u0639\u062f \u0627\u0648\u0631 \u0641\u0627\u0633\u0641\u0648\u0631\u0633 \u06a9\u0645\u06cc \u063a\u0630\u0627\u0626\u06cc \u06c1\u06cc\u0645\u0648\u06af\u0644\u0648\u0628\u06cc\u0646 \u06cc\u0648\u0631\u06cc\u0627 \u06a9\u06cc \u0639\u0644\u0627\u0645\u062a \u06c1\u0648 \u0633\u06a9\u062a\u06cc \u06c1\u06d2\u06d4","Urgent vet differential diagnosis (blood smear/lab tests). Treat cause-specific: anti-protozoals and tick control for babesiosis, or phosphorus therapy plus mineral correction for deficiency-related cases, with fluids/supportive care.","\u0641\u0648\u0631\u06cc \u0648\u06cc\u0679 \u0688\u0641\u0631\u06cc\u0646\u0634\u0644 \u062a\u0634\u062e\u06cc\u0635 (\u0628\u0644\u0688 \u0627\u0633\u0645\u0626\u06cc\u0631/\u0644\u06cc\u0628 \u0679\u06cc\u0633\u0679) \u0636\u0631\u0648\u0631\u06cc \u06c1\u06d2\u06d4 \u0648\u062c\u06c1 \u06a9\u06d2 \u0645\u0637\u0627\u0628\u0642 \u0639\u0644\u0627\u062c \u06a9\u0631\u06cc\u06ba: \u0628\u06cc\u0628\u06cc\u0633\u06cc\u0648\u0633\u0633 \u0645\u06cc\u06ba \u0627\u06cc\u0646\u0679\u06cc \u067e\u0631\u0648\u0679\u0648\u0632\u0648\u0644 \u0627\u0648\u0631 \u0679\u0650\u06a9 \u06a9\u0646\u0679\u0631\u0648\u0644\u060c \u062c\u0628\u06a9\u06c1 \u06a9\u0645\u06cc \u0648\u0627\u0644\u06d2 \u06a9\u06cc\u0633 \u0645\u06cc\u06ba \u0641\u0627\u0633\u0641\u0648\u0631\u0633 \u062a\u06be\u0631\u0627\u067e\u06cc \u0627\u0648\u0631 \u0645\u0646\u0631\u0644 \u062f\u0631\u0633\u062a\u06af\u06cc\u060c \u0633\u0627\u062a\u06be \u0641\u0644\u0648\u0626\u0688/\u0633\u067e\u0648\u0631\u0679\u0648 \u06a9\u06cc\u0626\u0631\u06d4"],t.w)
B.ZQ=new A.l(B.af,["Milk Fever (Hypocalcemia)","\u0645\u0644\u06a9 \u0641\u06cc\u0648\u0631 (\u06c1\u0627\u0626\u067e\u0648\u06a9\u06cc\u0644\u0633\u06cc\u0645\u0627)","Weakness after calving, cold ears, tremors, inability to stand, low appetite.","\u0628\u0686\u06d2 \u06a9\u06d2 \u0628\u0639\u062f \u06a9\u0645\u0632\u0648\u0631\u06cc\u060c \u06a9\u0627\u0646 \u0679\u06be\u0646\u0688\u06d2\u060c \u06a9\u067e\u06a9\u067e\u06cc\u060c \u06a9\u06be\u0691\u0627 \u0646\u06c1 \u06c1\u0648 \u067e\u0627\u0646\u0627\u060c \u0628\u06be\u0648\u06a9 \u06a9\u0645 \u06c1\u0648\u0646\u0627\u06d4","Emergency calcium therapy by veterinarian, warm bedding, careful lifting support and transition mineral balance in diet.","\u0648\u06cc\u0679\u0631\u0646\u0631\u06cc\u0646 \u06a9\u06d2 \u0630\u0631\u06cc\u0639\u06d2 \u06c1\u0646\u06af\u0627\u0645\u06cc \u06a9\u06cc\u0644\u0634\u06cc\u0645 \u062a\u06be\u0631\u0627\u067e\u06cc\u060c \u06af\u0631\u0645 \u0628\u0686\u06be\u0648\u0646\u0627\u060c \u0627\u062d\u062a\u06cc\u0627\u0637 \u0633\u06d2 \u0627\u0679\u06be\u0627\u0646\u06d2 \u06a9\u06cc \u0633\u067e\u0648\u0631\u0679 \u0627\u0648\u0631 \u062e\u0648\u0631\u0627\u06a9 \u0645\u06cc\u06ba \u0679\u0631\u0627\u0646\u0632\u06cc\u0634\u0646 \u0645\u0646\u0631\u0644 \u062a\u0648\u0627\u0632\u0646\u06d4"],t.w)
