B.a_3=new A.l(B.af,["Foot-and-Mouth Disease (FMD)","\u0645\u0646\u06c1 \u06a9\u06be\u0631 \u06a9\u06cc \u0628\u06cc\u0645\u0627\u0631\u06cc (FMD)","Fever, mouth lesions, hoof pain, salivation, reduced milk and appetite.","\u0628\u062e\u0627\u0631\u060c \u0645\u0646\u06c1 \u06a9\u06d2 \u0632\u062e\u0645\u060c \u06a9\u06be\u0631 \u0645\u06cc\u06ba \u062f\u0631\u062f\u060c \u0631\u0627\u0644\u060c \u062f\u0648\u062f\u06be \u0627\u0648\u0631 \u0628\u06be\u0648\u06a9 \u0645\u06cc\u06ba \u06a9\u0645\u06cc\u06d4","Supportive treatment, soft feed, hoof care, biosecurity isolation; maintain vaccine boosters.","\u0633\u067e\u0648\u0631\u0679\u0648 \u0639\u0644\u0627\u062c\u060c \u0646\u0631\u0645 \u062e\u0648\u0631\u0627\u06a9\u060c \u06a9\u06be\u0631 \u06a9\u06cc \u062f\u06cc\u06a9\u06be \u0628\u06be\u0627\u0644\u060c \u0628\u0627\u06cc\u0648 \u0633\u06a9\u06cc\u0648\u0631\u0679\u06cc \u06a9\u06d2 \u0633\u0627\u062a\u06be \u0639\u0644\u06cc\u062d\u062f\u06af\u06cc\u061b \u0648\u06cc\u06a9\u0633\u06cc\u0646 \u0628\u0648\u0633\u0679\u0631 \u062c\u0627\u0631\u06cc \u0631\u06a9\u06be\u06cc\u06ba\u06d4"],t.w)
B.ZN=new A.l(B.af,["Lumpy Skin Disease (LSD)","\u0644\u0645\u067e\u06cc \u0627\u0633\u06a9\u0646 \u0628\u06cc\u0645\u0627\u0631\u06cc (LSD)","Skin nodules, fever, swollen lymph nodes, reduced milk production.","\u062c\u0644\u062f \u067e\u0631 \u06af\u0644\u0679\u06cc\u0627\u06ba\u060c \u0628\u062e\u0627\u0631\u060c \u0644\u0645\u0641 \u0646\u0648\u0688 \u0633\u0648\u062c\u0646\u060c \u062f\u0648\u062f\u06be \u0645\u06cc\u06ba \u06a9\u0645\u06cc\u06d4","Vet-supervised supportive therapy, wound care, fly/tick control, and vaccination of at-risk animals.","\u0648\u06cc\u0679 \u06a9\u06cc \u0646\u06af\u0631\u0627\u0646\u06cc \u0645\u06cc\u06ba \u0633\u067e\u0648\u0631\u0679\u0648 \u0639\u0644\u0627\u062c\u060c \u0632\u062e\u0645 \u06a9\u06cc \u062f\u06cc\u06a9\u06be \u0628\u06be\u0627\u0644\u060c \u0645\u06a9\u06be\u06cc/\u0679\u0650\u06a9 \u06a9\u0646\u0679\u0631\u0648\u0644\u060c \u0627\u0648\u0631 \u062e\u0637\u0631\u06d2 \u0648\u0627\u0644\u06d2 \u062c\u0627\u0646\u0648\u0631\u0648\u06ba \u06a9\u06cc \u0648\u06cc\u06a9\u0633\u06cc\u0646\u06d4"],t.w)
B.a_2=new A.l(B.af,["Mastitis","\u062a\u06be\u0646 \u06a9\u06cc \u0633\u0648\u0632\u0634 (\u0645\u0627\u0633\u0679\u0627\u0626\u0679\u0633)","Udder swelling, abnormal milk, pain during milking, sudden yield drop.","\u062a\u06be\u0646 \u0633\u0648\u062c\u0646\u060c \u063a\u06cc\u0631 \u0645\u0639\u0645\u0648\u0644\u06cc \u062f\u0648\u062f\u06be\u060c \u062f\u0648\u062f\u06be \u0646\u06a9\u0627\u0644\u062a\u06d2 \u0648\u0642\u062a \u062f\u0631\u062f\u060c \u0627\u0686\u0627\u0646\u06a9 \u067e\u06cc\u062f\u0627\u0648\u0627\u0631 \u0645\u06cc\u06ba \u06a9\u0645\u06cc\u06d4","Prompt mastitis testing, vet medication protocol, teat dipping and improved milking hygiene.","\u0641\u0648\u0631\u06cc \u0645\u0627\u0633\u0679\u0627\u0626\u0679\u0633 \u0679\u06cc\u0633\u0679\u060c \u0648\u06cc\u0679 \u06a9\u06d2 \u0645\u0637\u0627\u0628\u0642 \u0627\u062f\u0648\u06cc\u0627\u062a\u060c \u0679\u06cc\u0679 \u0688\u0650\u067e \u0627\u0648\u0631 \u062f\u0648\u062f\u06be \u0646\u06a9\u0627\u0644\u0646\u06d2 \u06a9\u06cc \u0635\u0641\u0627\u0626\u06cc \u0628\u06c1\u062a\u0631 \u06a9\u0631\u06cc\u06ba\u06d4"],t.w)
B.ZU=new A.l(B.af,[u.Z,u.I,"Coffee/red urine, weakness, anemia and milk drop; fever/tick exposure suggest babesiosis, while peri-parturient cows with poor mineral intake may have phosphorus-deficiency hemoglobinuria.","\u06a9\u0627\u0641\u06cc/\u0633\u0631\u062e \u067e\u06cc\u0634\u0627\u0628\u060c \u06a9\u0645\u0632\u0648\u0631\u06cc\u060c \u062e\u0648\u0646 \u06a9\u06cc \u06a9\u0645\u06cc \u0627\u0648\u0631 \u062f\u0648\u062f\u06be \u0645\u06cc\u06ba \u06a9\u0645\u06cc\u061b \u0628\u062e\u0627\u0631/\u0679\u0650\u06a9 \u0627\u06cc\u06a9\u0633\u067e\u0648\u0698\u0631 \u0628\u06cc\u0628\u06cc\u0633\u06cc\u0648\u0633\u0633 \u06a9\u06cc \u0637\u0631\u0641 \u0627\u0634\u0627\u0631\u06c1 \u06a9\u0631\u062a\u0627 \u06c1\u06d2 \u062c\u0628\u06a9\u06c1 \u0628\u0686\u06d2 \u06a9\u06d2 \u0642\u0631\u06cc\u0628 \u06af\u0627\u0626\u06cc\u06ba \u0645\u06cc\u06ba \u06a9\u0645 \u0645\u0646\u0631\u0644 \u062e\u0648\u0631\u0627\u06a9 \u0641\u0627\u0633\u0641\u0648\u0631\u0633 \u06a9\u0645\u06cc \u06c1\u06cc\u0645\u0648\u06af\u0644\u0648\u0628\u06cc\u0646 \u06cc\u0648\u0631\u06cc\u0627 \u06a9\u0627 \u0633\u0628\u0628 \u0628\u0646 \u0633\u06a9\u062a\u06cc \u06c1\u06d2\u06d4","Confirm cause with veterinarian (smear/biochemistry). Use anti-babesial therapy + tick control for babesiosis, or phosphorus supplementation and dietary mineral balancing for deficiency cases, with supportive fluids.","\u0648\u06cc\u0679\u0631\u0646\u0631\u06cc\u0646 \u0633\u06d2 \u0648\u062c\u06c1 \u06a9\u06cc \u062a\u0635\u062f\u06cc\u0642 \u06a9\u0631\u06cc\u06ba (\u0627\u0633\u0645\u0626\u06cc\u0631/\u0628\u0627\u06cc\u0648\u06a9\u06cc\u0645\u0633\u0679\u0631\u06cc)\u06d4 \u0628\u06cc\u0628\u06cc\u0633\u06cc\u0648\u0633\u0633 \u0645\u06cc\u06ba \u0627\u06cc\u0646\u0679\u06cc \u0628\u06cc\u0628\u06cc\u0633\u06cc\u0626\u0644 \u0639\u0644\u0627\u062c + \u0679\u0650\u06a9 \u06a9\u0646\u0679\u0631\u0648\u0644\u060c \u062c\u0628\u06a9\u06c1 \u06a9\u0645\u06cc \u0648\u0627\u0644\u06d2 \u06a9\u06cc\u0633 \u0645\u06cc\u06ba \u0641\u0627\u0633\u0641\u0648\u0631\u0633 \u0633\u067e\u0644\u06cc\u0645\u0646\u0679 \u0627\u0648\u0631 \u062e\u0648\u0631\u0627\u06a9\u06cc \u0645\u0646\u0631\u0644 \u0628\u06cc\u0644\u0646\u0633\u060c \u0633\u0627\u062a\u06be \u0633\u067e\u0648\u0631\u0679\u0648 \u0641\u0644\u0648\u0626\u0688\u0632 \u062f\u06cc\u06ba\u06d4"],t.w)
B.ZY=new A.l(B.af,["Milk Fever (Hypocalcemia)","\u0645\u0644\u06a9 \u0641\u06cc\u0648\u0631 (\u06c1\u0627\u0626\u067e\u0648\u06a9\u06cc\u0644\u0633\u06cc\u0645\u0627)","Usually near calving: muscle weakness, staggering, low body temperature, recumbency.","\u0627\u06a9\u062b\u0631 \u0628\u0686\u06d2 \u06a9\u06d2 \u0642\u0631\u06cc\u0628: \u067e\u0679\u06be\u0648\u06ba \u06a9\u06cc \u06a9\u0645\u0632\u0648\u0631\u06cc\u060c \u0644\u0691\u06a9\u06be\u0691\u0627\u06c1\u0679\u060c \u062c\u0633\u0645\u0627\u0646\u06cc \u062f\u0631\u062c\u06c1 \u062d\u0631\u0627\u0631\u062a \u06a9\u0645\u060c \u0644\u06cc\u0679 \u062c\u0627\u0646\u0627\u06d4","Immediate IV/oral calcium under vet supervision, monitor heart rate, and adjust pre-calving mineral feeding.","\u0648\u06cc\u0679 \u0646\u06af\u0631\u0627\u0646\u06cc \u0645\u06cc\u06ba \u0641\u0648\u0631\u06cc \u0622\u0626\u06cc \u0648\u06cc/\u0627\u0648\u0631\u0644 \u06a9\u06cc\u0644\u0634\u06cc\u0645\u060c \u062f\u0644 \u06a9\u06cc \u062f\u06be\u0691\u06a9\u0646 \u0645\u0627\u0646\u06cc\u0679\u0631 \u06a9\u0631\u06cc\u06ba\u060c \u0627\u0648\u0631 \u0628\u0686\u06d2 \u0633\u06d2 \u067e\u06c1\u0644\u06d2 \u0645\u0646\u0631\u0644 \u0641\u06cc\u0688\u0646\u06af \u062f\u0631\u0633\u062a \u06a9\u0631\u06cc\u06ba\u06d4"],t.w)
B.a_4=new A.l(B.af,["Grass Tetany (Hypomagnesemia)","\u06af\u0631\u0627\u0633 \u0679\u06cc\u0679\u0646\u06cc (\u06c1\u0627\u0626\u067e\u0648 \u0645\u06cc\u06af\u0646\u06cc\u0634\u06cc\u0645\u06cc\u0627)","Excitability, muscle tremors, stiff gait, teeth grinding, sudden convulsions.","\u0632\u06cc\u0627\u062f\u06c1 \u0628\u06d2 \u0686\u06cc\u0646\u06cc\u060c \u067e\u0679\u06be\u0648\u06ba \u06a9\u06cc \u06a9\u067e\u06a9\u067e\u06cc\u060c \u0627\u06a9\u0691\u06cc \u06c1\u0648\u0626\u06cc \u0686\u0627\u0644\u060c \u062f\u0627\u0646\u062a \u067e\u06cc\u0633\u0646\u0627\u060c \u0627\u0686\u0627\u0646\u06a9 \u062f\u0648\u0631\u06d2\u06d4","Urgent magnesium treatment by veterinarian, reduce stress, provide oral magnesium follow-up and correct mineral imbalance in ration.","\u0648\u06cc\u0679\u0631\u0646\u0631\u06cc\u0646 \u06a9\u06d2 \u0630\u0631\u06cc\u0639\u06d2 \u0641\u0648\u0631\u06cc \u0645\u06cc\u06af\u0646\u06cc\u0634\u06cc\u0645 \u0639\u0644\u0627\u062c\u060c \u062a\u0646\u0627\u0624 \u06a9\u0645 \u06a9\u0631\u06cc\u06ba\u060c \u0628\u0639\u062f \u0627\u0632\u0627\u06ba \u0627\u0648\u0631\u0644 \u0645\u06cc\u06af\u0646\u06cc\u0634\u06cc\u0645 \u062f\u06cc\u06ba \u0627\u0648\u0631 \u062e\u0648\u0631\u0627\u06a9\u06cc \u0645\u0646\u0631\u0644 \u0639\u062f\u0645 \u062a\u0648\u0627\u0632\u0646 \u062f\u0631\u0633\u062a \u06a9\u0631\u06cc\u06ba\u06d4"],t.w)
B.ZZ=new A.l(B.af,["Liver Fluke (Fasciolosis)","\u062c\u06af\u0631 \u06a9\u06cc \u0633\u0646\u0688\u06cc (\u0641\u06cc\u0634\u06cc\u0648\u0644\u0648\u0633\u0633)","Chronic weight loss, pale mucosa, poor body condition, diarrhea and milk decline.","\u062f\u0627\u0626\u0645\u06cc \u0648\u0632\u0646 \u0645\u06cc\u06ba \u06a9\u0645\u06cc\u060c \u062c\u06be\u0644\u06cc\u0627\u06ba \u067e\u06cc\u0644\u06cc\u060c \u062c\u0633\u0645\u0627\u0646\u06cc \u062d\u0627\u0644\u062a \u062e\u0631\u0627\u0628\u060c \u0627\u0633\u06c1\u0627\u0644 \u0627\u0648\u0631 \u062f\u0648\u062f\u06be \u0645\u06cc\u06ba \u06a9\u0645\u06cc\u06d4","Fecal/lab confirmation, stage-appropriate flukicide protocol, nutrition correction and drainage of wet grazing patches to break fluke cycle.","\u0641\u06cc\u06a9\u0644/\u0644\u06cc\u0628 \u062a\u0635\u062f\u06cc\u0642\u060c \u0645\u0631\u062d\u0644\u06d2 \u06a9\u06d2 \u0645\u0637\u0627\u0628\u0642 \u0641\u0644\u0648\u06a9 \u06a9\u0634 \u067e\u0631\u0648\u0679\u0648\u06a9\u0648\u0644\u060c \u063a\u0630\u0627\u0626\u06cc \u062f\u0631\u0633\u062a\u06af\u06cc \u0627\u0648\u0631 \u06af\u06cc\u0644\u06cc \u0686\u0631\u0627\u06af\u0627\u06c1 \u06a9\u06d2 \u0646\u06a9\u0627\u0633 \u0633\u06d2 \u0641\u0644\u0648\u06a9 \u0633\u0627\u0626\u06cc\u06a9\u0644 \u062a\u0648\u0691\u06cc\u06ba\u06d4"],t.w)
