B.a1h=new A.l(B.bO,["\u0639\u0645\u0648\u0645\u0627\u064b \u062c\u0648\u0646 \u062a\u0627 \u062c\u0648\u0644\u0627\u0626\u06cc\u061b \u06af\u0631\u0645 \u0639\u0644\u0627\u0642\u0648\u06ba \u0645\u06cc\u06ba \u06a9\u0686\u06be \u0641\u0635\u0644\u06cc\u06ba \u0645\u0626\u06cc \u06a9\u06d2 \u0622\u062e\u0631 \u0633\u06d2 \u0622\u0628\u067e\u0627\u0634\u06cc \u06a9\u06d2 \u0633\u0627\u062a\u06be \u0634\u0631\u0648\u0639 \u06c1\u0648 \u0633\u06a9\u062a\u06cc \u06c1\u06cc\u06ba\u06d4","\u0639\u0645\u0648\u0645\u0627\u064b \u0627\u06a9\u062a\u0648\u0628\u0631 \u062a\u0627 \u0646\u0648\u0645\u0628\u0631\u061b \u0679\u06be\u0646\u0688\u06d2 \u0639\u0644\u0627\u0642\u0648\u06ba \u0645\u06cc\u06ba \u06af\u0646\u062f\u0645/\u062c\u0648 \u06a9\u06cc \u0628\u0648\u0627\u0626\u06cc \u062f\u0633\u0645\u0628\u0631 \u06a9\u06d2 \u0622\u063a\u0627\u0632 \u062a\u06a9 \u0628\u0691\u06be \u0633\u06a9\u062a\u06cc \u06c1\u06d2\u06d4"],t.w)
B.a1k=new A.l(B.bO,["\u0639\u0645\u0648\u0645\u0627\u064b \u0627\u067e\u0631\u06cc\u0644 \u062a\u0627 \u062c\u0648\u0646 \u06a9\u06cc\u0648\u0646\u06a9\u06c1 \u06af\u0631\u0645\u06cc \u062c\u0644\u062f \u0634\u0631\u0648\u0639 \u06c1\u0648\u062a\u06cc \u06c1\u06d2\u061b \u0632\u06cc\u0631\u06cc\u06ba \u0633\u0646\u062f\u06be \u0645\u06cc\u06ba \u06a9\u067e\u0627\u0633/\u0686\u0627\u0648\u0644 \u06a9\u06cc \u06a9\u0627\u0634\u062a \u0639\u0645\u0648\u0645\u0627\u064b \u067e\u06c1\u0644\u06d2 \u0634\u0631\u0648\u0639 \u06c1\u0648\u062a\u06cc \u06c1\u06d2\u06d4","\u0639\u0645\u0648\u0645\u0627\u064b \u0627\u06a9\u062a\u0648\u0628\u0631 \u062a\u0627 \u062f\u0633\u0645\u0628\u0631\u061b \u0628\u0627\u0644\u0627\u0626\u06cc \u0633\u0646\u062f\u06be \u0645\u06cc\u06ba \u0646\u0645\u06cc \u06a9\u06cc \u062f\u0633\u062a\u06cc\u0627\u0628\u06cc \u067e\u0631 \u06a9\u0686\u06be \u0641\u0635\u0644\u06cc\u06ba \u062c\u0644\u062f \u0628\u06be\u06cc \u0644\u06af \u0633\u06a9\u062a\u06cc \u06c1\u06cc\u06ba\u06d4"],t.w)
B.a1l=new A.l(B.bO,["\u0639\u0645\u0648\u0645\u0627\u064b \u0645\u0626\u06cc \u062a\u0627 \u062c\u0648\u0644\u0627\u0626\u06cc\u061b \u0645\u06cc\u062f\u0627\u0646\u06cc \u0627\u0648\u0631 \u067e\u06c1\u0627\u0691\u06cc \u0639\u0644\u0627\u0642\u0648\u06ba \u0645\u06cc\u06ba \u0628\u0644\u0646\u062f\u06cc \u06a9\u06d2 \u0645\u0637\u0627\u0628\u0642 \u0627\u0648\u0642\u0627\u062a \u0645\u062e\u062a\u0644\u0641 \u06c1\u0648\u062a\u06d2 \u06c1\u06cc\u06ba\u06d4","\u0639\u0645\u0648\u0645\u0627\u064b \u0627\u06a9\u062a\u0648\u0628\u0631 \u062a\u0627 \u0646\u0648\u0645\u0628\u0631\u061b \u0628\u0644\u0646\u062f \u0639\u0644\u0627\u0642\u0648\u06ba \u0645\u06cc\u06ba \u06a9\u0686\u06be \u0641\u0635\u0644\u0648\u06ba \u06a9\u06d2 \u0627\u0648\u0642\u0627\u062a \u0628\u06c1\u0627\u0631\u06cc \u0646\u0638\u0627\u0645 \u06a9\u06cc \u0637\u0631\u0641 \u0645\u0646\u062a\u0642\u0644 \u06c1\u0648 \u0633\u06a9\u062a\u06d2 \u06c1\u06cc\u06ba\u06d4"],t.w)
B.a1o=new A.l(B.bO,["\u0639\u0645\u0648\u0645\u0627\u064b \u0627\u067e\u0631\u06cc\u0644 \u062a\u0627 \u062c\u0648\u0646 (\u0622\u0628\u067e\u0627\u0634 \u0648\u0627\u062f\u06cc\u0648\u06ba \u0645\u06cc\u06ba)\u061b \u0628\u0627\u0631\u0627\u0646\u06cc \u0639\u0644\u0627\u0642\u0648\u06ba \u0645\u06cc\u06ba \u0648\u0642\u062a \u0645\u0642\u0627\u0645\u06cc \u0628\u0627\u0631\u0634 \u067e\u0631 \u0632\u06cc\u0627\u062f\u06c1 \u0645\u0646\u062d\u0635\u0631 \u06c1\u0648\u062a\u0627 \u06c1\u06d2\u06d4","\u0639\u0645\u0648\u0645\u0627\u064b \u0627\u06a9\u062a\u0648\u0628\u0631 \u062a\u0627 \u0646\u0648\u0645\u0628\u0631\u061b \u0633\u0631\u062f \u0628\u0627\u0644\u0627\u0626\u06cc \u0639\u0644\u0627\u0642\u0648\u06ba \u0645\u06cc\u06ba \u0648\u0642\u062a \u06a9\u0686\u06be \u062a\u0627\u062e\u06cc\u0631 \u06cc\u0627 \u0628\u06c1\u0627\u0631\u06cc \u0634\u06cc\u0688\u0648\u0644 \u06a9\u06cc \u0637\u0631\u0641 \u062c\u0627 \u0633\u06a9\u062a\u0627 \u06c1\u06d2\u06d4"],t.w)
B.a1d=new A.l(B.bO,["\u0648\u0627\u062f\u06cc\u0648\u06ba \u0645\u06cc\u06ba \u0639\u0645\u0648\u0645\u0627\u064b \u0645\u0626\u06cc \u062a\u0627 \u062c\u0648\u0646\u060c \u062c\u0628 \u067e\u0627\u0644\u0627 \u06a9\u0645 \u06c1\u0648 \u062c\u0627\u0626\u06d2\u06d4","\u0645\u062e\u062a\u0635\u0631 \u0627\u0648\u0631 \u0628\u0644\u0646\u062f\u06cc \u0633\u06d2 \u0645\u062a\u0627\u062b\u0631\u061b \u0628\u06c1\u062a \u0633\u06cc \u0641\u0635\u0644\u0648\u06ba \u0645\u06cc\u06ba \u0645\u0642\u0627\u0645\u06cc \u0628\u0644\u0646\u062f \u0639\u0644\u0627\u0642\u06d2 \u06a9\u06d2 \u0634\u06cc\u0688\u0648\u0644 \u067e\u0631 \u0639\u0645\u0644 \u06a9\u06cc\u0627 \u062c\u0627\u062a\u0627 \u06c1\u06d2\u06d4"],t.w)
